import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import NavbarComponent from "../components/Navbar";
import { HostelAuthApi } from "../apis/hostel";
import { ParentAuthApi } from "../apis/parent";
import { StudentAuthApi } from "../apis/student";

const LandingPage = () => {
    // navigate
    const navigate = useNavigate()

    // use effect for login or not checking
    useEffect(() => {
        async function auth() {
            const admin = localStorage.getItem("admin")
            if (admin === "hostel") {
                const token = localStorage.getItem("hosteltoken")
                if (token) {
                    const auth = await HostelAuthApi(token)
                    if (auth && auth.status === "success" && auth.auth) {
                        navigate("/")
                    }
                }
            } else if (admin === "parent") {
                const token = localStorage.getItem("parenttoken")
                if (token) {
                    const auth = await ParentAuthApi(token)
                    if (auth && auth.status === "success" && auth.auth) {
                        navigate("/")
                    }
                }
            } else {
                const token = localStorage.getItem("studenttoken")
                if (token) {
                    const auth = await StudentAuthApi(token)
                    if (auth && auth.status === "success" && auth.auth) {
                        navigate("/")
                    }
                }
            }
        }
        auth()
    }, []);

    // handle submit
    const handleSubmit = (admin) => {
        localStorage.setItem("admin", admin)
        if (admin === "hostel") {
            navigate("/hostel/login")   
        } else if (admin === "parent") {
            navigate("/parent/login")
        } else {
            navigate("/login")
        }
    }

    // return
    return (
        <>
            <NavbarComponent now={''} />
            <div className="relative flex w-full h-screen justify-center items-center bg-gray-100 px-4">
                {/* Content */}
                <div className="relative flex">
                    <div
                        onClick={() => handleSubmit('student')}
                        style={{ bakc }}
                        className="flex w-72 h-40 mr-3 justify-center items-center border-2 border-yellow-500 hover:bg-yellow-500 text-white hover:text-black rounded-lg px-10 py-10 font-bold text-lg uppercase"
                    >
                        <h1>Student</h1>
                    </div>
                    <div
                        onClick={() => handleSubmit('parent')}
                        className="flex w-72 h-40 ml-3 justify-center items-center border-2 border-yellow-500 hover:bg-yellow-500 text-white hover:text-black rounded-lg px-10 py-10 font-bold text-lg uppercase"
                    >
                        <h1>Parent</h1>
                    </div>
                    <div
                        onClick={() => handleSubmit('hostel')}
                        className="flex w-72 h-40 ml-3 justify-center items-center border-2 border-yellow-500 hover:bg-yellow-500 text-white hover:text-black rounded-lg px-10 py-10 font-bold text-lg uppercase"
                    >
                        <h1>Hostel</h1>
                    </div>
                </div>
            </div>
        </>
    );
}

export default LandingPage;
